import 'package:flutter/material.dart';
import '../models/user_model.dart';
import '../services/api_client.dart';

class AuthProvider extends ChangeNotifier {
  final ApiClient _apiClient = ApiClient();

  User? _currentUser;
  String? _token;
  bool _isLoading = false;
  String? _errorMessage;

  User? get currentUser => _currentUser;
  String? get token => _token;
  bool get isLoading => _isLoading;
  String? get errorMessage => _errorMessage;
  bool get isAuthenticated => _currentUser != null && _token != null;

  Future<bool> signup({
    required String username,
    required String email,
    required String password,
    required String fullName,
  }) async {
    _isLoading = true;
    _errorMessage = null;
    notifyListeners();

    try {
      final response = await _apiClient.signup(
        username: username,
        email: email,
        password: password,
        fullName: fullName,
        bio: '',
        profilePicture: '',
      );

      if (response['success'] == true) {
        _token = response['token'];
        _currentUser = User(
          id: response['user']['id'],
          username: response['user']['username'],
          email: response['user']['email'],
          fullName: response['user']['fullName'],
          bio: response['user']['bio'] ?? '',
          profilePicture: response['user']['profilePicture'] ?? '',
          followerCount: 0,
          followingCount: 0,
          postCount: 0,
          isFollowing: false,
        );
        notifyListeners();
        return true;
      } else {
        _errorMessage = response['message'] ?? 'Signup failed';
        notifyListeners();
        return false;
      }
    } catch (e) {
      _errorMessage = 'Error: ${e.toString()}';
      notifyListeners();
      return false;
    } finally {
      _isLoading = false;
      notifyListeners();
    }
  }

  Future<bool> login({
    required String email,
    required String password,
  }) async {
    _isLoading = true;
    _errorMessage = null;
    notifyListeners();

    try {
      final response = await _apiClient.login(
        email: email,
        password: password,
      );

      if (response['success'] == true) {
        _token = response['token'];
        _currentUser = User(
          id: response['user']['id'],
          username: response['user']['username'],
          email: response['user']['email'],
          fullName: response['user']['fullName'],
          bio: response['user']['bio'] ?? '',
          profilePicture: response['user']['profilePicture'] ?? '',
          followerCount: response['user']['followerCount'] ?? 0,
          followingCount: response['user']['followingCount'] ?? 0,
          postCount: response['user']['postCount'] ?? 0,
          isFollowing: false,
        );
        notifyListeners();
        return true;
      } else {
        _errorMessage = response['message'] ?? 'Login failed';
        notifyListeners();
        return false;
      }
    } catch (e) {
      _errorMessage = 'Error: ${e.toString()}';
      notifyListeners();
      return false;
    } finally {
      _isLoading = false;
      notifyListeners();
    }
  }

  void logout() {
    _currentUser = null;
    _token = null;
    _errorMessage = null;
    notifyListeners();
  }

  void clearError() {
    _errorMessage = null;
    notifyListeners();
  }
}

  // Instance methods for non-static context
  Future<Map<String, dynamic>> signup({
    required String username,
    required String email,
    required String password,
    required String fullName,
    String bio = '',
    String profilePicture = '',
  }) async {
    try {
      final response = await http.post(
        Uri.parse('$baseUrl/auth/register'),
        headers: _getHeaders(),
        body: jsonEncode({
          'v_username': username,
          'v_name': fullName,
          'email': email,
          'password': password,
          'bio': bio,
          'profilePicture': profilePicture,
        }),
      );

      if (response.statusCode == 201) {
        final data = jsonDecode(response.body);
        _token = data['token'];
        return {
          'success': true,
          'token': data['token'],
          'user': data['user'] ?? {
            'id': data['v_id'],
            'username': data['v_username'],
            'fullName': data['v_name'],
            'email': data['email'],
            'bio': data['bio'] ?? '',
            'profilePicture': data['profilePicture'] ?? '',
          }
        };
      } else {
        return {
          'success': false,
          'message': jsonDecode(response.body)['message'] ?? 'Registration failed'
        };
      }
    } catch (e) {
      return {
        'success': false,
        'message': 'Error: ${e.toString()}'
      };
    }
  }

  Future<Map<String, dynamic>> loginWithEmail({
    required String email,
    required String password,
  }) async {
    try {
      final response = await http.post(
        Uri.parse('$baseUrl/auth/login'),
        headers: _getHeaders(),
        body: jsonEncode({
          'email': email,
          'password': password,
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        _token = data['token'];
        return {
          'success': true,
          'token': data['token'],
          'user': data['user'] ?? {
            'id': data['v_id'],
            'username': data['v_username'],
            'fullName': data['v_name'],
            'email': data['email'],
            'bio': data['bio'] ?? '',
            'profilePicture': data['profilePicture'] ?? '',
            'followerCount': data['followerCount'] ?? 0,
            'followingCount': data['followingCount'] ?? 0,
            'postCount': data['postCount'] ?? 0,
          }
        };
      } else {
        return {
          'success': false,
          'message': jsonDecode(response.body)['message'] ?? 'Login failed'
        };
      }
    } catch (e) {
      return {
        'success': false,
        'message': 'Error: ${e.toString()}'
      };
    }
  }

